INSERT INTO forum_posts (user_id, title, content, category) VALUES (1, 'مقاطعة الشرح بين البنين والبنات', 'اليوم لاحظت أن الأولاد يقاطعون أكثر أثناء الشرح، بينما البنات ينتظرن الإذن. كيف أتعامل مع هذا الوضع بطريقة عادلة؟', 'مواقف');
INSERT INTO forum_posts (user_id, title, content, category) VALUES (2, 'طريقة توزيع الأسئلة بالتناوب', 'استعملت طريقة توزيع الأسئلة بالتناوب بين البنات والبنين، ولاحظت تحسناً كبيراً في مستوى مشاركة البنات اللاتي كنّ يكتفين بالصمت.', 'تجارب');
INSERT INTO forum_posts (user_id, title, content, category) VALUES (3, 'الفرق بين الاختلاف الفردي والتصور الجندري', 'كيف يمكننا التفرقة بين الاختلاف الفردي الطبيعي والتصورات الجندرية النمطية أثناء التقييم الدراسي؟', 'أسئلة');
